// === Calculator_Age - N8N Code Node ===
const input = $input.first().json;
const raw = input.birthDate;

if (!raw || typeof raw !== 'string') {
  return [{ json: { erro: true, mensagem: "Campo birthDate ausente ou inválido." } }];
}

// Suporta DD/MM/YYYY e YYYY-MM-DD
let day, month, year;
if (raw.includes('/')) {
  [day, month, year] = raw.split('/').map(Number);
} else if (raw.includes('-')) {
  [year, month, day] = raw.split('-').map(Number);
} else {
  return [{ json: { erro: true, mensagem: `Formato não reconhecido: ${raw}` } }];
}

// Validação básica
if (!day || !month || !year || month < 1 || month > 12 || day < 1 || day > 31 || year < 1900) {
  return [{ json: { erro: true, mensagem: "Data de nascimento inválida." } }];
}

// Detecta rollover do JS (ex: 30/02 vira 02/03)
const birthDate = new Date(year, month - 1, day);
if (birthDate.getDate() !== day || birthDate.getMonth() !== month - 1 || birthDate.getFullYear() !== year) {
  return [{ json: { erro: true, mensagem: `Data inexistente: ${raw}` } }];
}

// Data de hoje zerada
const today = new Date();
const todayOnly = new Date(today.getFullYear(), today.getMonth(), today.getDate());

// Validação de data futura
if (birthDate > todayOnly) {
  return [{ json: { erro: true, mensagem: "Data de nascimento é no futuro." } }];
}

// Cálculo da idade
let years = todayOnly.getFullYear() - birthDate.getFullYear();
let months = todayOnly.getMonth() - birthDate.getMonth();
let days = todayOnly.getDate() - birthDate.getDate();

if (days < 0) {
  months--;
  const prevMonth = new Date(todayOnly.getFullYear(), todayOnly.getMonth(), 0);
  days += prevMonth.getDate();
}

if (months < 0) {
  years--;
  months += 12;
}

// Monta resposta legível
let descricao = '';
if (years > 0) descricao += `${years} ano${years > 1 ? 's' : ''}`;
if (months > 0) descricao += `${descricao ? ', ' : ''}${months} ${months > 1 ? 'meses' : 'mês'}`;
if (days > 0) descricao += `${descricao ? ' e ' : ''}${days} dia${days > 1 ? 's' : ''}`;
if (!descricao) descricao = 'Recém-nascido';

return [{
  json: {
    erro: false,
    anos: years,
    meses: months,
    dias: days,
    descricao,
    data_nascimento: raw
  }
}];

